function solve(n, edges, k) {
    class DSU {
        constructor(size) {
            this.parent = Array(size).fill().map((_, i) => i);
            this.rank = Array(size).fill(1);
        }
        find(x) {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x, y) {
            const xroot = this.find(x);
            const yroot = this.find(y);
            if (xroot === yroot) return;
            if (this.rank[xroot] < this.rank[yroot]) {
                this.parent[xroot] = yroot;
            } else {
                this.parent[yroot] = xroot;
                if (this.rank[xroot] === this.rank[yroot]) {
                    this.rank[xroot]++;
                }
            }
        }
    }

    edges.sort((a, b) => a[2] - b[2]);
    let low = 0;
    let high = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let answer = high;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= mid) {
                dsu.union(u, v);
            }
        }
        let components = 0;
        for (let i = 0; i < n; i++) {
            if (dsu.find(i) === i) {
                components++;
            }
        }
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
```

