#include <vector>
#include <algorithm>

struct DSU {
    std::vector<long long> parent, rank;
    DSU(long long size) {
        parent.resize(size);
        rank.resize(size);
        for (long long i = 0; i < size; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
    }
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union_(long long x, long long y) {
        long long xroot = find(x);
        long long yroot = find(y);
        if (xroot == yroot) return;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) {
                rank[xroot]++;
            }
        }
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    std::sort(edges.begin(), edges.end(), [](const std::vector<long long>& a, const std::vector<long long>& b) {
        return a[2] < b[2];
    });
    long long low = 0, high = edges.empty() ? 0 : edges.back()[2];
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] <= mid) {
                dsu.union_(e[0], e[1]);
            }
        }
        long long components = 0;
        for (long long i = 0; i < n; ++i) {
            if (dsu.find(i) == i) {
                components++;
            }
        }
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
